function vikas_startup_applications_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('vikas_startup_applications_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'startup_name' => Request::val('startup_name', ''),
		'email' => Request::val('email', ''),
		'incorporation_date' => Request::dateComponents('incorporation_date', '1'),
		'website_url' => Request::val('website_url', ''),
		'physical_address' => Request::val('physical_address', ''),
		'primary_contact_name' => Request::val('primary_contact_name', ''),
		'email_1' => Request::val('email_1', ''),
		'mobile_number' => Request::val('mobile_number', ''),
		'name_of_founders' => Request::val('name_of_founders', ''),
		'number_of_founders' => Request::val('number_of_founders', ''),
		'email_of_founders' => Request::val('email_of_founders', ''),
		'business_sector' => Request::val('business_sector', ''),
		'number_of_employees' => Request::val('number_of_employees', ''),
		'brief_description_of_service' => br2nl(Request::val('brief_description_of_service', '')),
		'mode_of_incubation' => Request::val('mode_of_incubation', ''),
		'type_of_workspace_desired' => br2nl(Request::val('type_of_workspace_desired', '')),
		'key_areas_of_support' => br2nl(Request::val('key_areas_of_support', '')),
		'declaration_form_link' => Request::val('declaration_form_link', ''),
		'is_your_start_up_dpiit_registered' => Request::val('is_your_start_up_dpiit_registered', ''),
		'incubation_status' => Request::val('incubation_status', ''),
		'datetime' => Request::datetime('datetime', ''),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('vikas_startup_applications_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		vikas_startup_applications_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

