function vikas_startup_applications_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('vikas_startup_applications_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: vikas_startup_applications_table_before_delete
	if(function_exists('vikas_startup_applications_table_before_delete')) {
		$args = [];
		if(!vikas_startup_applications_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `vikas_startup_applications_table` WHERE `id`='{$selected_id}'", $eo);

	// hook: vikas_startup_applications_table_after_delete
	if(function_exists('vikas_startup_applications_table_after_delete')) {
		$args = [];
		vikas_startup_applications_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='vikas_startup_applications_table' AND `pkValue`='{$selected_id}'", $eo);
}

