	$old_data = getRecord('vikas_startup_applications_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: vikas_startup_applications_table_before_update
	if(function_exists('vikas_startup_applications_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!vikas_startup_applications_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'vikas_startup_applications_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="vikas_startup_applications_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('vikas_startup_applications_table', $data['selectedID'], calculated_fields()['vikas_startup_applications_table']);

	// hook: vikas_startup_applications_table_after_update
	if(function_exists('vikas_startup_applications_table_after_update')) {
		if($row = getRecord('vikas_startup_applications_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!vikas_startup_applications_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('vikas_startup_applications_table', $selected_id);
